#!/usr/bin/env bun
/**
 * Benchmark Summary Script
 *
 * Parses bench-results.json (generated by `pnpm bench` or `pnpm bench:compat`)
 * and outputs a comparison table showing uniku performance vs npm alternatives.
 *
 * Usage:
 *   pnpm bench:summary        # Run after pnpm bench or pnpm bench:compat
 *   bun scripts/bench-summary.ts
 *
 * Output:
 *   - In CI (CI=true): Markdown table for GitHub PR comments
 *   - In terminal: Bun.inspect.table() with ANSI colors
 *
 * @module
 */

import { resolve } from 'node:path'
import {
  type BenchGroup,
  type Benchmark,
  type BenchResults,
  collectBenchGroups,
  formatOps,
  loadBenchResults,
} from './bench-results'

const isCI = Bun.env.CI === 'true'
const BENCH_RESULTS_PATH = resolve(import.meta.dir, '../bench-results.json')

let results: BenchResults
try {
  results = loadBenchResults(BENCH_RESULTS_PATH)
} catch (error) {
  if (error instanceof Error && 'code' in error && error.code === 'ENOENT') {
    console.error('Error: bench-results.json not found.')
    console.error("Run 'pnpm bench' first to generate benchmark results.")
  } else {
    console.error('Error: Failed to parse bench-results.json')
  }
  process.exit(1)
}

if (results.files.length === 0) {
  console.error('Error: No benchmark files found in results.')
  process.exit(1)
}

const groups = collectBenchGroups(results)

function parseGroupName(fullName: string): { category: string; name: string } | null {
  const match = fullName.match(/> (Generation|Validation) > (.+)$/)
  if (!match) return null
  return { category: match[1], name: match[2] }
}

// Threshold for considering performance roughly equivalent (5%)
const PARITY_THRESHOLD = 0.05
// Show warning indicator when RME exceeds this threshold
const RME_WARNING_THRESHOLD = 2.0

type ComparisonResult = {
  ratio: number
  unikuOps: string
  competitorOps: string
  comparison: string
  hasRmeWarning: boolean
  maxRme: number
}

function formatComparison(benchmarks: Benchmark[]): ComparisonResult {
  const uniku = benchmarks.find((b) => b.name === 'uniku')
  const npm = benchmarks.find((b) => b.name === 'npm')
  const regex = benchmarks.find((b) => b.name === 'regex')

  const competitor = npm ?? regex
  if (!uniku || !competitor) {
    return {
      ratio: 0,
      unikuOps: 'N/A',
      competitorOps: 'N/A',
      comparison: 'N/A',
      hasRmeWarning: false,
      maxRme: 0,
    }
  }

  const ratio = uniku.hz / competitor.hz
  const competitorName = npm ? 'npm' : 'regex'
  const maxRme = Math.max(uniku.rme ?? 0, competitor.rme ?? 0)
  const hasRmeWarning = maxRme > RME_WARNING_THRESHOLD

  let comparison: string
  if (ratio >= 1 - PARITY_THRESHOLD && ratio <= 1 + PARITY_THRESHOLD) {
    comparison = '~parity'
  } else if (ratio > 1) {
    const factor = ratio.toFixed(1).replace(/\.0$/, '')
    comparison = `**${factor}x faster**`
  } else {
    const factor = (1 / ratio).toFixed(1).replace(/\.0$/, '')
    comparison = `${competitorName} ${factor}x faster`
  }

  return {
    ratio,
    unikuOps: formatOps(uniku.hz),
    competitorOps: formatOps(competitor.hz),
    comparison,
    hasRmeWarning,
    maxRme,
  }
}

const generation: Map<string, ComparisonResult> = new Map()
const validation: Map<string, ComparisonResult> = new Map()
const internal: Map<string, BenchGroup> = new Map()

for (const group of groups) {
  const parsed = parseGroupName(group.fullName)
  if (!parsed) {
    internal.set(formatInternalGroupName(group.fullName), group)
    continue
  }

  const comparison = formatComparison(group.benchmarks)
  if (parsed.category === 'Generation') {
    generation.set(parsed.name, comparison)
  } else {
    validation.set(parsed.name, comparison)
  }
}

// Sort by performance ratio (faster first, then alphabetically)
const sortByPerformance = (a: [string, ComparisonResult], b: [string, ComparisonResult]) => {
  // Higher ratio = uniku is faster, sort descending
  if (a[1].ratio !== b[1].ratio) return b[1].ratio - a[1].ratio
  return a[0].localeCompare(b[0])
}

const generationSorted = [...generation.entries()].sort(sortByPerformance)
const validationSorted = [...validation.entries()].sort(sortByPerformance)
const internalSorted = [...internal.entries()].sort(([a], [b]) => a.localeCompare(b))

type TableRow = {
  name: string
  unikuOps: string
  competitorOps: string
  comparison: string
  hasRmeWarning: boolean
  maxRme: number
}

type InternalTableRow = {
  group: string
  name: string
  ops: string
  rme: string
}

// Build markdown table string with ops/s columns
function buildMarkdownTable(title: string, rows: TableRow[]): string {
  const lines: string[] = []
  lines.push(`### ${title}\n`)
  lines.push('| ID | uniku | npm/regex | Comparison |')
  lines.push('|-----|-------|-----------|------------|')
  for (const row of rows) {
    const warning = row.hasRmeWarning ? ` ⚠️ ±${row.maxRme.toFixed(1)}%` : ''
    lines.push(`| ${row.name} | ${row.unikuOps} ops/s | ${row.competitorOps} ops/s | ${row.comparison}${warning} |`)
  }
  return lines.join('\n')
}

function buildInternalMarkdownTable(rows: InternalTableRow[]): string {
  const lines: string[] = []
  lines.push('### Internal Benchmarks\n')
  lines.push('| Group | Benchmark | ops/s | RME |')
  lines.push('|-------|-----------|-------|-----|')
  for (const row of rows) {
    lines.push(`| ${row.group} | ${row.name} | ${row.ops} ops/s | ${row.rme} |`)
  }
  return lines.join('\n')
}

// Format comparison for terminal display with ANSI colors
function formatComparisonAnsi(comparison: string, hasWarning: boolean, maxRme: number): string {
  let result: string

  // Convert markdown bold to ANSI green bold
  if (comparison.includes('**')) {
    const match = comparison.match(/\*\*(.+)\*\*/)
    if (match) {
      result = `\x1b[1;32m${match[1]}\x1b[0m`
    } else {
      result = comparison
    }
  } else if (comparison === '~parity') {
    result = `\x1b[33m~parity\x1b[0m` // Yellow for parity
  } else if (comparison.includes('faster')) {
    result = `\x1b[31m${comparison}\x1b[0m` // Red for slower
  } else {
    result = comparison
  }

  // Add RME warning if applicable
  if (hasWarning) {
    result += ` \x1b[33m⚠️ ±${maxRme.toFixed(1)}%\x1b[0m`
  }

  return result
}

// Transform results to table rows
const generationRows: TableRow[] = generationSorted.map(([name, result]) => ({
  name,
  unikuOps: result.unikuOps,
  competitorOps: result.competitorOps,
  comparison: result.comparison,
  hasRmeWarning: result.hasRmeWarning,
  maxRme: result.maxRme,
}))

const validationRows: TableRow[] = validationSorted.map(([name, result]) => ({
  name,
  unikuOps: result.unikuOps,
  competitorOps: result.competitorOps,
  comparison: result.comparison,
  hasRmeWarning: result.hasRmeWarning,
  maxRme: result.maxRme,
}))

const internalRows: InternalTableRow[] = internalSorted.flatMap(([groupName, group]) =>
  [...group.benchmarks]
    .sort((a, b) => b.hz - a.hz)
    .map((benchmark) => ({
      group: groupName,
      name: benchmark.name,
      ops: formatOps(benchmark.hz),
      rme: `±${(benchmark.rme ?? 0).toFixed(1)}%`,
    })),
)

if (generationRows.length === 0 && validationRows.length === 0 && internalRows.length === 0) {
  console.log('No benchmark results to display.')
  process.exit(0)
}

if (isCI) {
  // In CI, output raw markdown for GitHub rendering
  console.log('## Benchmark Results\n')
  if (generationRows.length > 0) {
    console.log(buildMarkdownTable('Generation', generationRows))
  }
  if (validationRows.length > 0) {
    if (generationRows.length > 0) console.log()
    console.log(buildMarkdownTable('Validation', validationRows))
  }
  if (internalRows.length > 0) {
    if (generationRows.length > 0 || validationRows.length > 0) console.log()
    console.log(buildInternalMarkdownTable(internalRows))
  }
} else {
  // In terminal, use Bun.inspect.table() for clean formatting
  console.log('\x1b[1;36m## Benchmark Results\x1b[0m\n')

  if (generationRows.length > 0) {
    console.log('\x1b[1;33m### Generation\x1b[0m\n')
    console.log(
      Bun.inspect.table(
        generationRows.map((row) => ({
          ID: row.name,
          uniku: `${row.unikuOps} ops/s`,
          'npm/regex': `${row.competitorOps} ops/s`,
          Comparison: formatComparisonAnsi(row.comparison, row.hasRmeWarning, row.maxRme),
        })),
        { colors: true },
      ),
    )
  }

  if (validationRows.length > 0) {
    if (generationRows.length > 0) console.log()
    console.log('\x1b[1;33m### Validation\x1b[0m\n')
    console.log(
      Bun.inspect.table(
        validationRows.map((row) => ({
          ID: row.name,
          uniku: `${row.unikuOps} ops/s`,
          'npm/regex': `${row.competitorOps} ops/s`,
          Comparison: formatComparisonAnsi(row.comparison, row.hasRmeWarning, row.maxRme),
        })),
        { colors: true },
      ),
    )
  }

  if (internalRows.length > 0) {
    if (generationRows.length > 0 || validationRows.length > 0) console.log()
    console.log('\x1b[1;33m### Internal Benchmarks\x1b[0m\n')
    console.log(
      Bun.inspect.table(
        internalRows.map((row) => ({
          Group: row.group,
          Benchmark: row.name,
          'ops/s': row.ops,
          RME: row.rme,
        })),
        { colors: true },
      ),
    )
  }
}

function formatInternalGroupName(fullName: string): string {
  return fullName.replace(/^__tests__\/bench\/[^>]+ > /, '')
}
